    let error_of_json name json =
      match name with
      | "EncryptionTypeMismatch" ->
          `EncryptionTypeMismatch (EncryptionTypeMismatch.of_json json)
      | "InvalidRequest" -> `InvalidRequest (InvalidRequest.of_json json)
      | "InvalidWriteOffset" ->
          `InvalidWriteOffset (InvalidWriteOffset.of_json json)
      | "TooManyParts" -> `TooManyParts (TooManyParts.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "EncryptionTypeMismatch" ->
          `EncryptionTypeMismatch (EncryptionTypeMismatch.of_xml xml)
      | "InvalidRequest" -> `InvalidRequest (InvalidRequest.of_xml xml)
      | "InvalidWriteOffset" ->
          `InvalidWriteOffset (InvalidWriteOffset.of_xml xml)
      | "TooManyParts" -> `TooManyParts (TooManyParts.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `EncryptionTypeMismatch e ->
          `Assoc
            [("error", (`String "EncryptionTypeMismatch"));
            ("details", (EncryptionTypeMismatch.to_json e))]
      | `InvalidRequest e ->
          `Assoc
            [("error", (`String "InvalidRequest"));
            ("details", (InvalidRequest.to_json e))]
      | `InvalidWriteOffset e ->
          `Assoc
            [("error", (`String "InvalidWriteOffset"));
            ("details", (InvalidWriteOffset.to_json e))]
      | `TooManyParts e ->
          `Assoc
            [("error", (`String "TooManyParts"));
            ("details", (TooManyParts.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
