      let ifMatch =
        (Option.map ~f:IfMatch.of_xml) (Xml.child xml_arg0 "If-Match") in
      let bucket =
        BucketName.of_xml (Xml.child_exn ~context:context_ xml_arg0 "Bucket") in
      make ?checksumMode ?expectedBucketOwner ?partNumber ?requestPayer
        ?sSECustomerKeyMD5 ?sSECustomerKey ?sSECustomerAlgorithm ?versionId
        ?responseExpires ?responseContentType ?responseContentLanguage
        ?responseContentEncoding ?responseContentDisposition
        ?responseCacheControl ?range ~key ?ifUnmodifiedSince ?ifNoneMatch
        ?ifModifiedSince ?ifMatch ~bucket ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let checksumMode = field_map json__ "ChecksumMode" ChecksumMode.of_json in
      let expectedBucketOwner =
        field_map json__ "ExpectedBucketOwner" AccountId.of_json in
      let partNumber = field_map json__ "PartNumber" PartNumber.of_json in
      let requestPayer = field_map json__ "RequestPayer" RequestPayer.of_json in
      let sSECustomerKeyMD5 =
        field_map json__ "SSECustomerKeyMD5" SSECustomerKeyMD5.of_json in
      let sSECustomerKey =
        field_map json__ "SSECustomerKey" SSECustomerKey.of_json in
      let sSECustomerAlgorithm =
        field_map json__ "SSECustomerAlgorithm" SSECustomerAlgorithm.of_json in
      let versionId = field_map json__ "VersionId" ObjectVersionId.of_json in
      let responseExpires =
        field_map json__ "ResponseExpires" ResponseExpires.of_json in
      let responseContentType =
        field_map json__ "ResponseContentType" ResponseContentType.of_json in
      let responseContentLanguage =
        field_map json__ "ResponseContentLanguage"
          ResponseContentLanguage.of_json in
      let responseContentEncoding =
        field_map json__ "ResponseContentEncoding"
          ResponseContentEncoding.of_json in
      let responseContentDisposition =
        field_map json__ "ResponseContentDisposition"
          ResponseContentDisposition.of_json in
      let responseCacheControl =
        field_map json__ "ResponseCacheControl" ResponseCacheControl.of_json in
      let range = field_map json__ "Range" Range.of_json in
      let key = field_map_exn json__ "Key" ObjectKey.of_json in
