    let error_of_json name json =
      match name with
      | "NoSuchKey" -> `NoSuchKey (NoSuchKey.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "NoSuchKey" -> `NoSuchKey (NoSuchKey.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `NoSuchKey e ->
          `Assoc
            [("error", (`String "NoSuchKey"));
            ("details", (NoSuchKey.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let of_header_and_body =
      ((fun (xs, pipe) ->
          make
            ?deleteMarker:(Option.map
                             ((List.Assoc.find ~equal:String.Caseless.equal)
                                xs "x-amz-delete-marker")
                             ~f:DeleteMarker.of_string)
            ?acceptRanges:(Option.map
                             ((List.Assoc.find ~equal:String.Caseless.equal)
                                xs "accept-ranges") ~f:AcceptRanges.of_string)
            ?expiration:(Option.map
                           ((List.Assoc.find ~equal:String.Caseless.equal) xs
                              "x-amz-expiration") ~f:Expiration.of_string)
            ?restore:(Option.map
                        ((List.Assoc.find ~equal:String.Caseless.equal) xs
                           "x-amz-restore") ~f:Restore.of_string)
            ?archiveStatus:(Option.map
                              ((List.Assoc.find ~equal:String.Caseless.equal)
                                 xs "x-amz-archive-status")
                              ~f:ArchiveStatus.of_string)
            ?lastModified:(Option.map
                             ((List.Assoc.find ~equal:String.Caseless.equal)
                                xs "Last-Modified") ~f:LastModified.of_string)
            ?contentLength:(Option.map
                              ((List.Assoc.find ~equal:String.Caseless.equal)
                                 xs "Content-Length")
                              ~f:ContentLength.of_string)
            ?checksumCRC32:(Option.map
                              ((List.Assoc.find ~equal:String.Caseless.equal)
                                 xs "x-amz-checksum-crc32")
                              ~f:ChecksumCRC32.of_string)
            ?checksumCRC32C:(Option.map
